svg.script:
(function(){
  var svg = document.documentElement;
  var vb = [0,0,3200,3200];
  var drag = false, sx=0, sy=0, ox=0, oy=0;
  svg.addEventListener('mousedown', function(e){
    drag=true; sx=e.clientX; sy=e.clientY;
    ox=vb[0]; oy=vb[1];
  });
  svg.addEventListener('mousemove', function(e){
    if(!drag) return;
    var dx=(e.clientX-sx)*vb[2]/3200;
    var dy=(e.clientY-sy)*vb[3]/3200;
    vb[0]=ox-dx; vb[1]=oy-dy;
    svg.setAttribute('viewBox', vb.join(' '));
  });
  svg.addEventListener('mouseup', function(){ drag=false; });
  svg.addEventListener('wheel', function(e){
    e.preventDefault();
    var f = e.deltaY>0 ? 1.1 : 0.9;
    var mx=e.offsetX/3200*vb[2]+vb[0];
    var my=e.offsetY/3200*vb[3]+vb[1];
    vb[2]*=f; vb[3]*=f;
    vb[0]=mx-(mx-vb[0])*f; vb[1]=my-(my-vb[1])*f;
    svg.setAttribute('viewBox', vb.join(' '));
  }, {passive:false});
})();
